  function isDesktop(){ return window.matchMedia(DESKTOP).matches; }

  function disableClickOnToggle(toggle){
    // ЧТО гасим: любые попытки клика/клавиш на самом тоггле
    const cancel = (e) => { 
      if (!isDesktop()) return;           // мобилку не трогаем
      e.preventDefault(); 
      e.stopImmediatePropagation(); 
    };

    // мышь/pointer
    toggle.addEventListener('pointerdown', cancel, true);
    toggle.addEventListener('mousedown',   cancel, true);
    toggle.addEventListener('mouseup',     cancel, true);
    toggle.addEventListener('click',       cancel, true);

    // клавиатура (чтобы Enter/Space не триггерили клик)
    toggle.addEventListener('keydown', function(e){
      if (!isDesktop()) return;
      if (e.key === 'Enter' || e.key === ' ') cancel(e);
    }, true);

    // чисто косметика/а11y-подсказка
    toggle.setAttribute('aria-disabled','true'); 
  }

  function bind(){
    if (!isDesktop()) return;
    document.querySelectorAll(scopeToggles).forEach(disableClickOnToggle);
  }

  document.addEventListener('DOMContentLoaded', bind);
  // На случай ресайза между брейкпоинтами
  window.addEventListener('resize', function(){
    // Сначала снимаем старые (перезагрузка страницы — самый простой путь),
    // но для стабильности просто перебиндим: addEventListener с capture не дублируется критично.
    bind();
  });
})();
</script>
<style>
  /* Слои: overlay и меню поверх диммера, шапка — поверх всех */
  .w-nav-overlay {
    z-index: 1198 !important;
  }
  .w-nav-overlay .w-nav-menu {
    position: fixed;
    left: 0;
    right: 0;
    z-index: 1199 !important;
  }

  /* Диммер под меню */
  #menuDimmer {
    position: fixed;
    left: 0;
    right: 0;
    bottom: 0;
    background: rgba(0,0,0,.55);
    opacity: 0;
    pointer-events: none;
    transition: opacity .25s ease;
    z-index: 1197;
  }

  /* Когда меню открыто — фиксируем мобильную шапку и даём ей фон */
  body.mobile-menu-open .navbar-3 {
    position: fixed !important;
    top: 0;
    left: 0;
    right: 0;
    z-index: 1200 !important;
    transform: translateZ(0); /* страховка от глюков в FF */

    /* !!! тут поставь тот же фон, что у .header-container-2 !!! */
    background: #fff; /* пример, замени на свой цвет/градиент */
  }
</style>

<script>
/**
 * Mobile Webflow navbar — Firefox-safe:
 * - при открытии: фиксируем .navbar-3, считаем её высоту
 * - overlay и меню начинаются сразу под шапкой
 * - диммер #menuDimmer под меню
 * - скролл лочится через overflow, без position:fixed на body
 */
(function () {
  const NAVBAR = '.navbar-3';
  const BTN    = `${NAVBAR} .w-nav-button`;
  const OVSEL  = '.w-nav-overlay';
  const MENU   = '.w-nav-overlay .w-nav-menu';
  const MOBILE = '(max-width: 991px)';
  const isMobile = () => window.matchMedia(MOBILE).matches;

  // диммер
  let dimmer = document.getElementById('menuDimmer');
  if (!dimmer) {
    dimmer = document.createElement('div');
    dimmer.id = 'menuDimmer';
    document.body.appendChild(dimmer);
  }

  const $    = (s) => document.querySelector(s);
  const btn  = ()  => $(BTN);
  const ov   = ()  => $(OVSEL);
  const menu = ()  => $(MENU);
  const open = ()  => !!$(`${BTN}.w--open`);

  const lockScroll = () => {
    document.documentElement.style.overflow = 'hidden';
    document.body.style.overflow = 'hidden';
  };
  const unlockScroll = () => {
    document.documentElement.style.overflow = '';
    document.body.style.overflow = '';
  };

  function navHeight(){
    const el = $(NAVBAR);
    const h  = el ? Math.round(el.getBoundingClientRect().height) : 70;
    return h || 70;
  }

  function placeUnderHeader(){
    const h = navHeight();

    // гарантируем, что overlay в body (Firefox)
    const o = ov();
    if (o){
      if (o.parentNode !== document.body) document.body.appendChild(o);
      Object.assign(o.style, {
        position: 'fixed',
        top:      h + 'px',
        left:     '0',
        right:    '0',
        bottom:   '0',
        width:    '100%',
        overflow: 'visible',
        display:  'block',
        pointerEvents: 'auto'
      });
    }

    const m = menu();
    if (m){
      Object.assign(m.style, {
  position: 'fixed',
        top:       h + 'px',
        left:      '0',
        right:     '0',
      bottom:    '0',              // Растягиваем до низа
        overflowY: 'auto',           // Скролл только внутри меню
        maxHeight: 'none',           // Снимаем ограничения Webflow
        WebkitOverflowScrolling: 'touch' // Плавность на iOS
      });
    }

    dimmer.style.top = h + 'px';
  }

  function show(){
    if (!isMobile()) return;

    document.body.classList.add('mobile-menu-open');
    placeUnderHeader();

    dimmer.style.opacity       = '1';
    dimmer.style.pointerEvents = 'auto';

    lockScroll();
  }

function hide(){
  dimmer.style.opacity       = '0';
  dimmer.style.pointerEvents = 'none';

  document.body.classList.remove('mobile-menu-open');
  unlockScroll();

  const o = ov();
  if (o){ // ← убрали проверку !open()
    o.style.pointerEvents = 'none';
    o.style.display       = 'none';
    o.style.height        = ''; // сброс возможных залипаний FF
  }
}


  function sync(){
    if (!isMobile()) {
      hide();
      return;
    }
    if (open()) show(); else hide();
  }

  // клик по бургеру
  document.addEventListener('click', (e) => {
    if (e.target.closest(BTN)) {
      setTimeout(sync, 0);
    }
  });

  // клик по диммеру — закрываем меню
  dimmer.addEventListener('click', () => {
    const b = btn();
    if (b && b.classList.contains('w--open')) b.click();
  });

  // наблюдаем изменения классов/стилей от Webflow
  const mo = new MutationObserver(() => setTimeout(sync, 0));
  mo.observe(document.documentElement, {
    subtree: true,
    childList: true,
    attributes: true,
    attributeFilter: ['class', 'style', 'data-nav-menu-open']
  });

  // при ресайзе/скролле актуализируем позицию
  window.addEventListener('resize', () => {
    if (open()) placeUnderHeader();
    sync();
  }, { passive: true });

  window.addEventListener('scroll', () => {
    if (open()) placeUnderHeader();
  }, { passive: true });

  document.addEventListener('DOMContentLoaded', sync);
})();
</script>
<style>
  /* Глобальный стоп-кран:
     когда меню НЕ открыто (нет класса на body),
     оверлей полностью выключен и не ловит клики */
  body:not(.mobile-menu-open) .w-nav-overlay {
    display: none !important;
    pointer-events: none !important;
    height: auto !important;
  }

  /* Когда меню открыто — даём оверлею клики,
     чтобы работало само меню */
  body.mobile-menu-open .w-nav-overlay {
    pointer-events: auto !important;
  }
  

/* Улучшаем поведение скролла на мобильных */
body.mobile-menu-open .w-nav-overlay .w-nav-menu {
    -webkit-overflow-scrolling: touch;  /* Инерционный скролл для старых iOS */
}
</style></div></div><section class="section_breadcrumbs section-121"><div class="w-layout-blockcontainer container-default breadcrumbs-container w-container"><div class="breadcrumbs-wrapper"><a href="/" class="breadcrumb-link">Home</a><div class="breadcrumb-div">/</div><a href="/blog" class="breadcrumb-link hidden-link">Blog</a><div class="breadcrumb-div hidden-txt">/</div><div class="breadcrumb-text">5 Practical Techniques for Temporary Window Repair</div></div></div></section><section class="section hero-v4"><div class="w-layout-blockcontainer container-default w-container"><div class="blog-post-single---top-content"><div class="inner-container _770px"><div class="inner-container _550px---tablet"><div class="mg-top-small"><h1 class="display-9 mid">5 Practical Techniques for Temporary Window Repair</h1></div></div></div></div><div class="mg-top-extra-large"><div data-w-id="36d110dd-4070-3326-4ed6-4282e12132c4" style="opacity:0;-webkit-transform:translate3d(0, 0, 0) scale3d(0.92, 0.92, 1) rotateX(0) rotateY(0) rotateZ(0) skew(0, 0);-moz-transform:translate3d(0, 0, 0) scale3d(0.92, 0.92, 1) rotateX(0) rotateY(0) rotateZ(0) skew(0, 0);-ms-transform:translate3d(0, 0, 0) scale3d(0.92, 0.92, 1) rotateX(0) rotateY(0) rotateZ(0) skew(0, 0);transform:translate3d(0, 0, 0) scale3d(0.92, 0.92, 1) rotateX(0) rotateY(0) rotateZ(0) skew(0, 0)" class="image-wrapper border-radius-image-default"><img src="https://cdn.prod.website-files.com/6841ddf8ace3d9d9facb1586/6880f40d4ab4d1cbe2eb5a10_getty-images-xqFquocCtvE-unsplash%201.avif" loading="eager" alt="" class="image post---featured-image"/></div></div><div class="mg-top-section-large"><div class="inner-container _690px center"><div class="rich-text-v1 mg-bottom--16px w-richtext"><p>Home improvement projects always seem to be on the weekend agenda as a homeowner. Whether you&#x27;re new to the neighborhood or have been in your place for years, you likely have a running list somewhere of what needs tending to next.</p><p>Whatever your current list looks like, there are a few projects that, when they pop up unexpectedly, push everything else to the next season. Home window repair is one of those projects that could be equally intimidating and frustrating.</p><p>Perhaps &quot;replacing windows&quot; was on your home improvement list, but you were hoping to save for at least another year. Maybe you were told the previous owner had new windows installed a few years ago, but now that you&#x27;ve really settled in, you&#x27;ve noticed a few of the new windows are really drafty and your energy bill is much higher than you were expecting. Or, maybe you&#x27;ve had solid windows for some time, but your child accidentally broke a glass pane playing ball in the house again, and your warranty is up.</p><p>The frustrating news? Depending on the severity of the problem, you&#x27;ll still want to invest in a proper window replacement down the line. The relieving news? There are a variety of ways to temporarily fix your windows until you can find the right window experts for your needs and get a free, in-home estimate.</p><p>‍</p><h4>Here are 5 ways you can temporarily fix your windows, whether they&#x27;re leaky, drafty, broken, or cracked:</h4><p>‍</p><h5>1. Cover cracks with a tarp and tape</h5><p>You notice a crack in the glass of one of your windows after a particularly intense hail and ice storm. The glass hasn&#x27;t shattered into hundreds of pieces, but the crack is long and obvious. You&#x27;ve called up an expert to help replace the entire window, but they can&#x27;t get out there for a few days. What can you do in the meantime so that any additional winter weather doesn&#x27;t seep through and cause additional damage?</p><p>Head to the nearest hardware or home improvement store to pick up some heavy duty tape (duct tape works well due to its resistance to moisture) and either a thick plastic sheet or tarp. For only a few dollars, you can secure the cracked window and provide a temporary barrier to help prevent drafts and moisture from entering your home. While this may not be the most visually appealing temporary fix, you&#x27;ll be covered until you can get a full custom window replacement.</p><p>‍</p><h5>2. Create a makeshift plywood barrier</h5><p>You&#x27;ve noticed a crack in the glass of your townhome&#x27;s front-facing, ground-level window. There&#x27;s a lot of pedestrian traffic in your neighborhood, and you want to make sure your temporary repair keeps your window intact and your home safe. Plywood is another great option when dealing with broken windows.</p><p>Simply measure the window opening, cut the piece of plywood to fit the dimensions, and secure the makeshift barrier into place with screws, nails, or an adhesive. While this temporary fix might not add to your home&#x27;s curb appeal, it is temporary, and is typically an inexpensive fix. Your window will be protected from the elements and your home will be more secure until you can come up with a more permanent solution.</p><p>‍</p><h5>3. Re-caulk to stop any leaks and prevent damage</h5><p>You noticed the caulk around your windows is getting pretty bare. In fact, some of your windows have long cracks in their current caulk. You&#x27;ve noticed air seeping through on windy days, and you&#x27;re concerned that rain could also make its way inside next.</p><p>Re-caulking is an easy way to stop any potential long-term water damage from rain, melting snow, or ice, and treat leaky or drafty windows. This temporary fix is cost efficient, but will take up more of your time. You&#x27;ll want to remove the old caulk, and check the window frame underneath for mold and rot before adding new layers of this thick white glue. Be sure to give yourself plenty of time to allow the caulk to dry before rehanging curtains, shades, or blinds.</p><p>This is a great option if you live in a particularly cold region and need help preventing heat from escaping your home.</p><p>‍</p><h5>4. Add weather strips to stop drafts</h5><p>Once the weather turns chilly, it&#x27;s time to consider ways to keep drafty windows at bay. Weather strips are another great option to keep your home at the right temperature.</p><p>Found at your local hardware or home improvement store, weather strips are super easy to use and fairly inexpensive. One side of a weather strip is typically sticky and the other has a padded foam or plastic. After locking your windows in place, you&#x27;ll want to measure the length and width, cut the strips to the appropriate size, remove the sticker paper, and apply!</p><p>Remember this isn&#x27;t a permanent fix. You&#x27;ll need to replace the strips once the stickiness fades or the seasons change.</p><p>‍</p><h5>5. Pick up a temporary window repair kit for multiple needs</h5><p>Your cat clawed its way through the window screen, again. Luckily, there are repair kits out there that can help you patch the hole right up so insects and other critters don&#x27;t make their way inside on warmer days.</p><p>Some repair kits are specific to patching up window screen tears or holes, while others can help you ensure broken glass shards stay held together. Home window repair kits usually come with instructions and tools to help you DIY until quality window replacement experts, like Deluxe Windows, can stop by with a more permanent solution.</p><p>See current offers and schedule at free, no-obligation in-home consultation.</p></div></div></div></div></section><section class="section pd-120px"><div class="w-layout-blockcontainer container-default w-container"><div class="title-left---content-right"><div class="width-100-mobile-portrait"><h2 class="display-8 mid">Read More Articles</h2></div></div><div class="mg-top-large"><div class="w-dyn-list"><div role="list" class="collection-list-8 w-dyn-items"><div role="listitem" class="w-dyn-item"><a data-w-id="170402e1-59d1-d47e-3929-cc53ef18ac2e" href="/blog/why-vinyl-windows-are-the-smart-choice-for-bay-area-homeowners" class="blog-card-