 data-w-id="080cd6ed-2ec3-ab0f-3fec-cc4bec09a642" class="footer-v1---right-content"><div><div class="w-layout-grid footer-main-pages"><ul role="list" class="footer-column-links"><li class="footer-column-item"><a href="/about" class="footer-item-link w-inline-block"><div>About Us</div></a></li><li class="footer-column-item"><a href="/windows" class="footer-item-link w-inline-block"><div>Windows</div></a></li><li class="footer-column-item"><a href="#" class="footer-item-link w-inline-block"><div>Doors</div></a></li><li class="footer-column-item"><a href="/brand" class="footer-item-link w-inline-block"><div>Brands</div></a></li></ul><ul role="list" class="footer-column-links"><li class="footer-column-item"><a href="/glossary" class="footer-item-link w-inline-block"><div>Glossary</div></a></li><li class="footer-column-item"><a href="/contacts" class="footer-item-link w-inline-block"><div>Contacts Us</div></a></li><li class="footer-column-item"><a href="/testimonials" class="footer-item-link w-inline-block"><div>Testimonials</div></a></li><li class="footer-column-item"><a href="/financing" class="footer-item-link w-inline-block"><div>Financing</div></a></li></ul><ul id="w-node-_1ce59c11-5720-7953-47f7-4dd54673de6a-ec09a603" role="list" class="footer-column-links"><li class="footer-column-item"><a href="/faq" class="footer-item-link w-inline-block"><div>FAQs</div></a></li><li class="footer-column-item"><a href="/privacy-policy" class="footer-item-link w-inline-block"><div>Privacy Policy</div></a></li><li class="footer-column-item"><a href="/terms" class="footer-item-link w-inline-block"><div>Terms of Use</div></a></li></ul></div></div><p id="w-node-_49f8c755-3225-d40d-f9ab-cc9f4b368c44-ec09a603" class="paragraph">©2026 Deluxe Windows, Inc. <br/>All rights reserved.<br/></p></div><div id="w-node-_080cd6ed-2ec3-ab0f-3fec-cc4bec09a6ef-ec09a603" class="inner-container _380px _100-tablet"><div class="inner-container _450px---mbl"><div class="center-content---tablet"><div class="logo-wrapper v1"><a href="/" class="logo-link w-inline-block"><img src="https://cdn.prod.website-files.com/6841ddf8ace3d9d9facb14fd/686ad2b4b668ce59a9c25b0e_White.avif" alt="" sizes="(max-width: 719px) 100vw, 719px" srcset="https://cdn.prod.website-files.com/6841ddf8ace3d9d9facb14fd/686ad2b4b668ce59a9c25b0e_White-p-500.png 500w, https://cdn.prod.website-files.com/6841ddf8ace3d9d9facb14fd/686ad2b4b668ce59a9c25b0e_White.avif 719w"/></a></div></div></div></div></div></div></div></footer><script src="https://d3e54v103j8qbb.cloudfront.net/js/jquery-3.5.1.min.dc5e7f18c8.js?site=6841ddf8ace3d9d9facb14fd" type="text/javascript" integrity="sha256-9/aliU8dGd2tb6OSsuzixeV4y/faTqgFtohetphbbj0=" crossorigin="anonymous"></script><script src="https://cdn.prod.website-files.com/6841ddf8ace3d9d9facb14fd/js/webflow.schunk.172ec51a511480e2.js" type="text/javascript" integrity="sha384-qU8s0hexa7230yNvRC7SOXbAhsCCiiSAtnmgEod8Ssr0OB50VGzzWLiPDvmaspsW" crossorigin="anonymous"></script><script src="https://cdn.prod.website-files.com/6841ddf8ace3d9d9facb14fd/js/webflow.schunk.b35ad38f1af2d1dd.js" type="text/javascript" integrity="sha384-kPxhylkVGPto1495l5ywl0+XeOoRmw9z2/veWrv7DrZxLddZq3b5CSHy2Pbwu6QE" crossorigin="anonymous"></script><script src="https://cdn.prod.website-files.com/6841ddf8ace3d9d9facb14fd/js/webflow.edf23106.7ffc1f3e33d51fa2.js" type="text/javascript" integrity="sha384-wicn3eL0bgoqEmw1FcBYHYixtBTtjwr4B1GcFI4Kf5QwoQyupq1wtEgCOlE9CsW3" crossorigin="anonymous"></script><script>
(function () {

  /* ================================
     1. UTM CAPTURE (СРАЗУ)
  ================================= */
  const TRACK_PARAMS = [
    "utm_source","utm_medium","utm_campaign",
    "utm_term","utm_content","matchtype",
    "device","creative","gclid"
  ];

  const params = new URLSearchParams(window.location.search);
  const hasUtm = TRACK_PARAMS.some(p => params.get(p));

  if (hasUtm) {
    // Есть UTM в URL — перезаписываем чисто
    TRACK_PARAMS.forEach(param => {
      const value = params.get(param);
      if (value) {
        localStorage.setItem(`lead_param_${param}`, value);
      } else {
        localStorage.removeItem(`lead_param_${param}`);
      }
    });

  } else {
    // Нет UTM в URL — проверяем localStorage
    const hasSavedUtm = TRACK_PARAMS.some(p => localStorage.getItem(`lead_param_${p}`));

    if (!hasSavedUtm) {
      // Нет нигде — пишем SEO / organic / direct
      const ref = document.referrer || "";
      let searchEngine   = "";
      let organicKeyword = "";
      let refDomain      = "";

      try {
        if (ref) {
          const refUrl = new URL(ref);
          refDomain    = refUrl.hostname.replace(/^www\./, "");

          const SEO_ENGINES = {
            "google.com":     "google",
            "bing.com":       "bing",
            "yahoo.com":      "yahoo",
            "duckduckgo.com": "duckduckgo",
            "yandex.ru":      "yandex",
            "yandex.com":     "yandex",
            "baidu.com":      "baidu"
          };

          for (const [domain, name] of Object.entries(SEO_ENGINES)) {
            if (refDomain.includes(domain)) {
              searchEngine   = name;
              organicKeyword = refUrl.searchParams.get("q")
                || refUrl.searchParams.get("p")
                || refUrl.searchParams.get("query")
                || "(not provided)";
              break;
            }
          }
        }
      } catch(e) {}

      if (searchEngine) {
        localStorage.setItem("lead_param_utm_source", searchEngine);
        localStorage.setItem("lead_param_utm_medium", "organic");
        if (organicKeyword) localStorage.setItem("lead_param_utm_term", organicKeyword);
      } else if (refDomain && !refDomain.includes(window.location.hostname)) {
        localStorage.setItem("lead_param_utm_source", refDomain);
        localStorage.setItem("lead_param_utm_medium", "referral");
      } else {
        localStorage.setItem("lead_param_utm_source", "(direct)");
        localStorage.setItem("lead_param_utm_medium", "(none)");
      }
    }
    // Если hasSavedUtm — ничего не трогаем (first-touch)
  }

  if (!localStorage.getItem("lead_param_landing_page")) {
    localStorage.setItem("lead_param_landing_page", window.location.pathname);
  }


  /* ================================
     2. HIDDEN FIELDS (DOM READY)
  ================================= */
  function injectHiddenFields(form) {
    [...TRACK_PARAMS, "landing_page"].forEach(param => {
      if (!form.querySelector(`input[name="${param}"]`)) {
        const input = document.createElement("input");
        input.type = "hidden";
        input.name = param;
        input.value = localStorage.getItem(`lead_param_${param}`) || "";
        form.appendChild(input);
      }
    });
  }

  document.addEventListener("DOMContentLoaded", function () {
    document.querySelectorAll("form").forEach(injectHiddenFields);
  });


  /* ================================
     3. LAZY SYSTEM INIT
  ================================= */
  let lazyLoaded = false;

  function initLazy() {
    if (lazyLoaded) return;
    lazyLoaded = true;

    initDate();
    initForms();
    loadZoho();
  }

  window.addEventListener('scroll', initLazy, { once: true });
  window.addEventListener('click', initLazy, { once: true });
  setTimeout(initLazy, 4000);


  /* ================================
     4. DATE SCRIPT (LAZY)
  ================================= */
  function initDate() {
    const now = new Date();
    const lastDayDate = new Date(now.getFullYear(), now.getMonth() + 1, 0);

    const monthNames = [
      'January','February','March','April','May','June',
      'July','August','September','October','November','December'
    ];

    document.querySelectorAll('[data-last-day]').forEach(el => {
      const format = el.getAttribute('data-last-day');

      let text = '';
      const m = lastDayDate.getMonth() + 1;
      const d = lastDayDate.getDate();
      const y = lastDayDate.getFullYear();

      if (format === 'us-short') {
        text = `${m}/${d}/${String(y).slice(-2)}`;
      } else if (format === 'long') {
        text = `${monthNames[lastDayDate.getMonth()]} ${d}, ${y}`;
      }

      el.textContent = text;
    });
  }


  /* ================================
     5. FORM + IP + GOOGLE SHEETS
  ================================= */
  function initForms() {

    let ipData = {};
    let ipLoaded = false;

    function fetchIP() {
      return fetch('https://ipapi.co/json/')
        .then(r => r.json())
        .then(data => {
          ipLoaded = true;
          ipData = data;
        })
        .catch(() => ipLoaded = true);
    }

    function waitIP(timeout = 800) {
      return Promise.race([
        fetchIP(),
        new Promise(res => setTimeout(res, timeout))
      ]);
    }

    document.querySelectorAll('form').forEach(form => {

      form.addEventListener('submit', function () {

        waitIP().then(() => {

          const formData = new FormData(form);

          formData.append('ip_address', ipData.ip || '');
          formData.append('geo_location', ipData.city || '');

          const body = new URLSearchParams(formData);

          fetch('https://script.google.com/macros/s/AKfycbyJGhNROpBI8TUkGn9RtdNtIDxNjxsI52kyHgBtDIUauSEWgzVIqCFPic0-chwjxNxU/exec', {
            method: 'POST',
            body,
            keepalive: true
          });

          fetch('https://script.google.com/macros/s/AKfycbwp7eg4fm8OZtiHLjAFrbNyPaSyDjZWmfTJyhkiAZ2UsWYmE6l7euH9K0RtdgODH44Rmg/exec', {
            method: 'POST',
            body,
            keepalive: true
          });

        });

      });

    });
  }


  /* ================================
     6. ZOHO (LAZY)
  ================================= */
  function loadZoho() {
    const script = document.createElement('script');
    script.src = "https://salesiq.zohopublic.com/widget?wc=siqfe34762ee44eb77120f2a13c55fed7c0984ca603ae60aafcaf2adda4331dc65a";
    script.defer = true;
    document.body.appendChild(script);
  }

})();
</script>

